def grade_student(score):
    if score >=80:
       return "A"
    elif score >= 75:
        return "B"
    elif score >= 60:
        return "c"
    else :
        return "F"

# function calls
print("score 90 grade:", grade_student(90))
print(" score 85 grade:", grade_student(85))
print("score 50 grade:", grade_student(50))

def safe_divide(a, b):
    try:
        result = a / b
        return result

    except ZeroDivisionError:
        return "Error: Division by zero is not allowed."

    except TypeError:
        return "Error: Invalid input type."

# Function calls
print(safe_divide(10, 2))
print(safe_divide(10, 0))
print(safe_divide(10, "a"))

student_marks = {
    "Riya": 85,
    "Kriya": 92,
    "priya": 76
}

def get_marks(name):
    try:
        print(name, "marks:", student_marks[name])

    except KeyError:
        print("Student not found in the record.")

# Function calls
get_marks("Riya")
get_marks("kriya")
